import{_ as a,o as r,c as o,ag as e,ah as s}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"子智能体","description":"","frontmatter":{},"headers":[],"relativePath":"features/subagents.md","filePath":"features/subagents.md"}'),n={name:"features/subagents.md"};function l(d,t,i,h,g,c){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="子智能体" tabindex="-1">子智能体 <a class="header-anchor" href="#子智能体" aria-label="Permalink to &quot;子智能体&quot;">​</a></h1><p>子智能体（Sub-agent）是由主 Agent 派生出来的专项 Agent——主 Agent 在处理复杂任务时，可以将某个子任务交给子智能体独立执行，子任务完成后结果汇总回主流程。</p><blockquote><p>相关基础：<a href="/docs/features/conversation.html#子智能体卡片">对话面板 → 子智能体卡片</a></p></blockquote><div class="tip custom-block"><p class="custom-block-title">一个类比</p><p>可以把它想象成：AI 面对一个大工程时，自动雇了几位「专项小助手」分头干活——有人专门查资料、有人专门改代码——各自干完后向主 AI 汇报结果，主 AI 再汇总推进。</p></div><hr><h2 id="对话中的子智能体卡片" tabindex="-1">对话中的子智能体卡片 <a class="header-anchor" href="#对话中的子智能体卡片" aria-label="Permalink to &quot;对话中的子智能体卡片&quot;">​</a></h2><h3 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h3><p>每当主 Agent 派生一个子智能体，对话区会出现一张<strong>折叠卡片</strong>，将子智能体的完整对话过程封装在其中。v0.9.1 界面改版起，这张卡片采用「头卡 → 工作报告 → 完整流水」的<strong>三层渐进披露</strong>结构——默认只给一行概览，需要多少细节就展开多少。</p><h3 id="第一层-头卡" tabindex="-1">第一层：头卡 <a class="header-anchor" href="#第一层-头卡" aria-label="Permalink to &quot;第一层：头卡&quot;">​</a></h3><p>卡片折叠时只显示一行<strong>头卡</strong>：</p><ul><li>左侧为 ◈ 标记 + 子智能体名称（未指定专项名时显示「子智能体」）+ 子任务摘要</li><li><strong>运行中</strong>：名称旁出现「子 Agent 运行中」脉动徽标；**后台（异步）**子智能体完成后显示「后台」徽标</li><li>右侧依次为<strong>调用次数</strong>（如「5 次调用」）、耗时，以及一枚<strong>状态圆点</strong>——绿色 = 成功、红色 = 出错、橙色（脉动）= 运行中——和展开箭头</li></ul><p>若子智能体尚未产生任何输出，展开后会显示占位提示「等待子 Agent 输出…」。</p><h3 id="第二层-工作报告" tabindex="-1">第二层：工作报告 <a class="header-anchor" href="#第二层-工作报告" aria-label="Permalink to &quot;第二层：工作报告&quot;">​</a></h3><p>点击头卡（或按 Enter / Space）展开<strong>工作报告</strong>，从上到下依次是：</p><ol><li><strong>任务简报</strong>：主 Agent 派发给子智能体的任务说明</li><li><strong>回执</strong>（仅后台异步子智能体有）：派发时的确认回执</li><li><strong>过程摘要</strong>：一行「⚙ N 次调用」加各工具的调用次数统计（如 <code>Read×4 Grep×2</code>）；其下默认只保留<strong>最近 2 个产出型工具</strong>（写文件、编辑、命令等会改变工作区的调用）的卡片，查询型调用（读文件、搜索等）只计数不展示</li><li><strong>结果框</strong>：永远排在报告末尾——成功为绿色左条的「✓ 结果」，出错为红色左条的「✗ 结果」，内容为子智能体的最终汇报</li></ol><h3 id="第三层-完整流水" tabindex="-1">第三层：完整流水 <a class="header-anchor" href="#第三层-完整流水" aria-label="Permalink to &quot;第三层：完整流水&quot;">​</a></h3><p>想看全过程时，点击报告内的<strong>展开全部</strong>——子智能体的完整流水（思考、正文、全部工具调用）会以与主对话一致的排版逐条展开；点击<strong>收起全部</strong>回到精简报告。</p><div class="tip custom-block"><p class="custom-block-title">后台（异步）子智能体</p><p>主 Agent 也可以把子智能体放到<strong>后台</strong>异步执行（v0.9.0 起）。后台子智能体同样以这套卡片呈现，且<strong>默认折叠</strong>（底部后台状态条仍可见）、展开后内容实时流式出现；完成后主 Agent 通常会在主对话里给出一段友好的结果描述。详见<a href="/docs/features/background-tasks.html">后台任务活动</a>。</p></div><p><img src="'+s+'" alt="截图：对话面板中一张子智能体卡片已展开工作报告，可见任务简报、「⚙ N 次调用」过程摘要与末尾绿色「✓ 结果」框，右上角有「展开全部」按钮"></p><hr><h2 id="设置-→-子智能体" tabindex="-1">设置 → 子智能体 <a class="header-anchor" href="#设置-→-子智能体" aria-label="Permalink to &quot;设置 → 子智能体&quot;">​</a></h2><h3 id="这是什么-1" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么-1" aria-label="Permalink to &quot;这是什么&quot;">​</a></h3><p><strong>设置 → 子智能体</strong>页面是自定义子智能体的可视化管理中心，你可以在这里新建、编辑、启用/禁用、删除用户级和项目级子智能体，也可以查看插件提供的子智能体。</p><div class="tip custom-block"><p class="custom-block-title">按 CLI 家族切换</p><p>页面顶部有 <strong>Claude | Codex | OpenCode</strong> 切换栏，分别查看各 CLI 的子智能体（OpenCode 家族自 v0.9.0 起纳入）。<strong>只有 Claude 家族支持在应用内新建 / 编辑 / 删除</strong>；Codex 与 OpenCode 的子智能体为<strong>只读</strong>——本页仅列出它们并提供启用 / 禁用开关（OpenCode 的开关会改写对应文件的 frontmatter <code>disable</code>），不提供创建 / 编辑 / 删除入口，也不显示 Claude 家族才有的<strong>打开目录</strong>按钮，以免误改各 CLI 的目录。下文的新建 / 编辑 / 删除步骤均针对 Claude 家族。</p></div><p>子智能体按作用域分为三类：</p><table tabindex="0"><thead><tr><th>标签</th><th>含义</th></tr></thead><tbody><tr><td><strong>用户</strong></td><td>跨项目可用，存储在用户配置目录</td></tr><tr><td><strong>项目</strong></td><td>仅当前工作区可用（需有活动工作区）</td></tr><tr><td><strong>Plugin</strong>（界面原文）</td><td>由插件提供，因此只读，需在插件侧修改</td></tr></tbody></table><h3 id="在哪里打开" tabindex="-1">在哪里打开 <a class="header-anchor" href="#在哪里打开" aria-label="Permalink to &quot;在哪里打开&quot;">​</a></h3><p><strong>设置</strong>（右上角齿轮图标）→ 左侧导航 → <strong>子智能体</strong></p><h3 id="新建子智能体" tabindex="-1">新建子智能体 <a class="header-anchor" href="#新建子智能体" aria-label="Permalink to &quot;新建子智能体&quot;">​</a></h3><ol><li><p>点击右上角<strong>新建子智能体</strong>按钮，打开新建表单。</p></li><li><p>填写以下字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>只能包含字母、数字和连字符，长度 3–50 个字符</td></tr><tr><td><strong>颜色</strong></td><td>子智能体标识颜色（可选）</td></tr><tr><td><strong>作用域</strong></td><td>用户 / 项目（选项取决于是否有活动工作区）</td></tr><tr><td><strong>描述</strong></td><td>简要说明该子智能体的用途</td></tr><tr><td><strong>系统提示词</strong></td><td>指导子智能体行为的核心指令</td></tr><tr><td><strong>工具</strong></td><td>允许该子智能体使用的工具分组；不选则不限制，继承全部工具</td></tr><tr><td><strong>模型</strong></td><td>下拉选择，选项有 inherit、opus、sonnet、haiku；选 inherit 表示继承当前会话模型（选择器下方有提示「inherit 继承当前会话模型」）</td></tr></tbody></table></li><li><p>填写完成后点击<strong>保存</strong>，页面自动返回列表，新建的子智能体出现在列表中并提示「已新建 {name}」。</p></li></ol><h3 id="编辑子智能体" tabindex="-1">编辑子智能体 <a class="header-anchor" href="#编辑子智能体" aria-label="Permalink to &quot;编辑子智能体&quot;">​</a></h3><ol><li>在列表中找到目标子智能体，点击进入详情。</li><li>详情页显示名称、描述、系统提示词、作用域、状态、模型、工具、文件路径等所有字段。</li><li>点击<strong>编辑</strong>进入编辑表单，修改后保存即可，提示「已保存 {name}」。</li></ol><h3 id="启用-禁用" tabindex="-1">启用 / 禁用 <a class="header-anchor" href="#启用-禁用" aria-label="Permalink to &quot;启用 / 禁用&quot;">​</a></h3><p>在列表中切换每条子智能体右侧的开关，状态立即变为<strong>已启用</strong>或<strong>已禁用</strong>。被禁用的子智能体不会被主 Agent 调用。</p><h3 id="删除子智能体" tabindex="-1">删除子智能体 <a class="header-anchor" href="#删除子智能体" aria-label="Permalink to &quot;删除子智能体&quot;">​</a></h3><p>在详情页点击删除，弹出确认对话框：</p><blockquote><p>「确定删除「{name}」？文件将移入回收站。」</p></blockquote><p>确认后文件移入系统回收站，列表刷新并提示「已删除 {name}」。</p><div class="tip custom-block"><p class="custom-block-title">项目级子智能体需有活动工作区</p><p>新建「项目」作用域的子智能体时，需要先在主界面打开一个工作区，否则选项置灰并提示「需有活动工作区」。</p></div><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解子智能体之后，可以继续了解 LoongCode 的权限体系，前往<a href="/docs/features/permissions.html">权限管理</a>继续学习。</p>',42)])])}const b=a(n,[["render",l]]);export{u as __pageData,b as default};
